"""
OrangeTree Global — AI Reservation Chat Agent (UC10)
Powered by Claude API (Anthropic)
Run: streamlit run uc10_reservation_agent.py
"""

import streamlit as st
import anthropic
import json
from datetime import datetime

LOGO_B64 = ""
LOGO_HTML = '<img src="data:image/svg+xml;base64,' + LOGO_B64 + '" style="width:100%;max-width:220px;display:block;margin-bottom:4px;">'

st.set_page_config(
    page_title="Reservation Agent | OrangeTree Global",
    page_icon="🌳",
    layout="wide",
)

st.markdown("""
<style>
    .section-header {
        border-left: 4px solid #F36621;
        padding: 0.3rem 0.8rem;
        background: #fff3ee;
        border-radius: 0 4px 4px 0;
        margin: 1.2rem 0 0.6rem 0;
        font-weight: 600;
    }
    .booking-card {
        background: #f0fff4;
        border: 2px solid #1A7A30;
        border-radius: 8px;
        padding: 1rem 1.2rem;
        margin-top: 1rem;
    }
    .booking-title {
        color: #1A7A30;
        font-size: 1.1rem;
        font-weight: 700;
        margin-bottom: 0.5rem;
    }
    .stChatMessage { border-radius: 8px; }
</style>
""", unsafe_allow_html=True)

st.markdown(
    f'<img src="data:image/svg+xml;base64,{LOGO_B64}" style="width:280px;max-width:100%;display:block;margin-bottom:12px;">',
    unsafe_allow_html=True
)
st.markdown("## AI Reservation Chat Agent")
st.markdown("A conversational booking agent for restaurants, clinics, salons and more — collects all booking details and confirms.")
st.divider()

with st.sidebar:
    st.markdown(LOGO_HTML, unsafe_allow_html=True)
    st.markdown("---")
    api_key = st.text_input("Anthropic API Key", type="password", help="Get from console.anthropic.com")
    model = st.selectbox("Model", ["claude-opus-4-8", "claude-sonnet-4-6", "claude-haiku-4-5-20251001"], index=2,
        help="Haiku is fast and responsive for chat")
    st.markdown("---")
    st.markdown("**Business Setup**")
    business_name = st.text_input("Business name", placeholder="Bhawanipur House")
    business_type = st.selectbox("Business type", [
        "Restaurant / Dining", "Cafe / Coffee Shop", "Clinic / Medical",
        "Salon / Spa", "Hotel / Guesthouse", "Fitness / Gym", "Other"
    ])
    opening_hours = st.text_input("Opening hours", placeholder="Mon-Sat 11am-10pm, Sun 12pm-9pm")
    capacity_note = st.text_input("Capacity / slots note", placeholder="Tables for 2-20 guests, last booking 9pm")
    special_notes = st.text_area("Special info for the agent", 
        placeholder="We do not accept reservations for fewer than 2 guests. Call +91 XXXXX for large parties (15+).",
        height=80)
    st.markdown("---")
    if st.button("Reset conversation", use_container_width=True):
        st.session_state["messages"] = []
        st.session_state["booking"] = {}
        st.rerun()
    st.info("UC10 of OrangeTree's AI SME Suite. Powered by Claude API.", icon="ℹ️")

if "messages" not in st.session_state:
    st.session_state["messages"] = []
if "booking" not in st.session_state:
    st.session_state["booking"] = {}

col_chat, col_booking = st.columns([2, 1], gap="large")

with col_chat:
    st.markdown('<div class="section-header">Customer Chat</div>', unsafe_allow_html=True)

    for msg in st.session_state["messages"]:
        with st.chat_message(msg["role"]):
            st.markdown(msg["content"])

    user_input = st.chat_input("Type your message...")

    if user_input:
        st.session_state["messages"].append({"role": "user", "content": user_input})

        if not api_key:
            st.error("Enter your Anthropic API key in the sidebar.")
        else:
            biz = business_name if business_name.strip() else "our venue"
            btype = business_type
            hours = opening_hours if opening_hours.strip() else "our standard hours"
            cap = capacity_note if capacity_note.strip() else ""
            notes = special_notes if special_notes.strip() else ""

            system = f"""You are the booking agent for {biz}, a {btype}.

Your job is to help customers make a reservation by collecting:
1. Date and time requested
2. Number of guests (or appointment type for clinics/salons)
3. Customer name
4. Contact number or email

Business hours: {hours}
{f"Capacity notes: {cap}" if cap else ""}
{f"Special notes: {notes}" if notes else ""}

Once you have all 4 details, confirm the booking clearly with a summary.
Be friendly, concise, and professional. If a requested slot seems outside hours or capacity, politely advise.

After you have collected all booking details, include this JSON block at the end of your response (hidden from customer):
BOOKING_DATA:{{"name":"...","date":"...","time":"...","guests":"...","contact":"...","confirmed":true}}

If you don't have all details yet, do not include the BOOKING_DATA block."""

            messages_for_api = []
            for m in st.session_state["messages"]:
                messages_for_api.append({"role": m["role"], "content": m["content"]})

            with st.spinner("Agent typing..."):
                client = anthropic.Anthropic(api_key=api_key)
                resp = client.messages.create(
                    model=model,
                    max_tokens=600,
                    system=system,
                    messages=messages_for_api
                )

            reply = resp.content[0].text

            # Extract booking data if present
            if "BOOKING_DATA:" in reply:
                parts = reply.split("BOOKING_DATA:")
                visible_reply = parts[0].strip()
                try:
                    booking_json = parts[1].strip()
                    st.session_state["booking"] = json.loads(booking_json)
                except Exception:
                    pass
            else:
                visible_reply = reply

            st.session_state["messages"].append({"role": "assistant", "content": visible_reply})
            st.rerun()

with col_booking:
    st.markdown('<div class="section-header">Booking Summary</div>', unsafe_allow_html=True)

    booking = st.session_state.get("booking", {})

    if booking.get("confirmed"):
        biz_display = business_name if business_name.strip() else "Venue"
        st.markdown(
            '<div class="booking-card">' +
            '<div class="booking-title">Booking Confirmed</div>' +
            f'<div><b>Venue:</b> {biz_display}</div>' +
            f'<div><b>Guest:</b> {booking.get("name", "—")}</div>' +
            f'<div><b>Date:</b> {booking.get("date", "—")}</div>' +
            f'<div><b>Time:</b> {booking.get("time", "—")}</div>' +
            f'<div><b>Guests:</b> {booking.get("guests", "—")}</div>' +
            f'<div><b>Contact:</b> {booking.get("contact", "—")}</div>' +
            '</div>',
            unsafe_allow_html=True
        )

        booking_text = f"""RESERVATION CONFIRMATION
========================
Venue: {biz_display}
Guest: {booking.get("name", "")}
Date: {booking.get("date", "")}
Time: {booking.get("time", "")}
Guests: {booking.get("guests", "")}
Contact: {booking.get("contact", "")}
Confirmed: {datetime.now().strftime("%d/%m/%Y %H:%M")}
"""
        st.download_button(
            "Download Confirmation",
            data=booking_text,
            file_name="reservation_confirmation.txt",
            mime="text/plain",
            use_container_width=True
        )
    else:
        st.markdown("**Pending details:**")
        fields = [
            ("Name", booking.get("name")),
            ("Date", booking.get("date")),
            ("Time", booking.get("time")),
            ("Guests", booking.get("guests")),
            ("Contact", booking.get("contact")),
        ]
        for label, val in fields:
            icon = "✓" if val else "○"
            st.markdown(f"{icon} **{label}:** {val if val else '_not yet collected_'}")

        if not st.session_state["messages"]:
            st.info("Start a conversation to begin the booking.", icon="ℹ️")

    st.markdown("---")
    st.markdown("**Conversation history**")
    st.caption(f"{len(st.session_state['messages'])} messages")

st.caption("OrangeTree Global | AI SME Suite — UC10: Reservation Chat Agent")
